const body = $json.body ?? $json;
const text = String(body.text ?? '').trim();

const kv = {};
for (const token of text.split(/\s+/)) {
  if (!token.includes('=')) continue;
  const [k, ...rest] = token.split('=');
  if (!k || rest.length === 0) continue;
  kv[k.trim().toLowerCase()] = rest.join('=').trim();
}

const pick = (key, fallback = '') => {
  const v = body[key] ?? kv[key];
  if (v === undefined || v === null || v === '') return fallback;
  return v;
};

const toInt = (value, dflt, min, max) => {
  const n = Number.parseInt(String(value ?? ''), 10);
  if (Number.isNaN(n)) return dflt;
  return Math.max(min, Math.min(max, n));
};

const rawCountry = String(pick('country', $json.default_country || 'ALL')).toUpperCase();
const country = rawCountry === 'PAN-AFRICA' ? 'PAN' : rawCountry;

const sectorInput = String(pick('sector', $json.default_sector || 'ALL')).trim();
const sector = sectorInput ? (sectorInput === 'ALL' ? 'ALL' : sectorInput[0].toUpperCase() + sectorInput.slice(1).toLowerCase()) : 'ALL';

const region = String(pick('region', $json.default_region || 'all')).toLowerCase();
const theme = String(pick('theme', $json.default_theme || '')).trim();
const audience = String(pick('audience', $json.default_audience || 'IOA leadership')).trim();

const days = toInt(pick('days', $json.default_days || 7), $json.default_days || 7, 1, 30);
const maxArticles = toInt(pick('max_articles', $json.default_max_articles || 120), $json.default_max_articles || 120, 20, 250);
const minRelevance = toInt(pick('min_relevance', $json.default_min_relevance || 3), $json.default_min_relevance || 3, 1, 5);

const requester = String(body.user_name || body.user_id || body.requester || 'unknown').trim();

return [{
  json: {
    ...$json,
    country,
    sector,
    region,
    theme,
    audience,
    days,
    max_articles: maxArticles,
    min_relevance: minRelevance,
    requester,
    requested_at_utc: new Date().toISOString()
  }
}];

const sinceIso = new Date(Date.now() - ($json.days * 24 * 60 * 60 * 1000)).toISOString();

const select = encodeURIComponent('raw_id,country,sector,relevance_score,relevance_reason,summary,enriched_at,raw:raw_articles!inner(url,headline,source_name,published_at,scraped_at)');
const params = [
  `select=${select}`,
  `relevance_score=gte.${$json.min_relevance}`,
  `enriched_at=gte.${encodeURIComponent(sinceIso)}`,
  `order=${encodeURIComponent('relevance_score.desc,enriched_at.desc')}`,
  `limit=${$json.max_articles}`
];

if ($json.country && $json.country !== 'ALL') {
  params.push(`country=eq.${encodeURIComponent($json.country)}`);
}

if ($json.sector && $json.sector !== 'ALL') {
  params.push(`sector=eq.${encodeURIComponent($json.sector)}`);
}

const supabaseQueryUrl = `${$json.supabase_url}/rest/v1/enriched_articles?${params.join('&')}`;

return [{
  json: {
    ...$json,
    since_iso: sinceIso,
    supabase_query_url: supabaseQueryUrl
  }
}];

const req = $items('Parse Request Filters', 0, 0)[0].json;

const inputItems = $input.all();
let rows = [];

for (const it of inputItems) {
  if (Array.isArray(it.json)) {
    rows.push(...it.json);
  } else if (it.json && Array.isArray(it.json.data)) {
    rows.push(...it.json.data);
  } else if (it.json && Array.isArray(it.json.body)) {
    rows.push(...it.json.body);
  } else if (it.json && it.json.body && Array.isArray(it.json.body.data)) {
    rows.push(...it.json.body.data);
  } else if (it.json && typeof it.json === 'object' && (it.json.raw_id || it.json.id)) {
    rows.push(it.json);
  }
}

const regionByCountry = {
  DZ: 'north-africa', EG: 'north-africa', LY: 'north-africa', MA: 'north-africa', SD: 'north-africa', TN: 'north-africa',
  BJ: 'west-africa', BF: 'west-africa', CI: 'west-africa', CV: 'west-africa', GH: 'west-africa', GM: 'west-africa', GN: 'west-africa',
  GW: 'west-africa', LR: 'west-africa', ML: 'west-africa', MR: 'west-africa', NE: 'west-africa', NG: 'west-africa', SN: 'west-africa',
  SL: 'west-africa', TG: 'west-africa',
  BI: 'east-africa', DJ: 'east-africa', ER: 'east-africa', ET: 'east-africa', KE: 'east-africa', RW: 'east-africa', SO: 'east-africa',
  SS: 'east-africa', TZ: 'east-africa', UG: 'east-africa', SC: 'east-africa', KM: 'east-africa',
  AO: 'central-africa', CD: 'central-africa', CF: 'central-africa', CG: 'central-africa', CM: 'central-africa', GA: 'central-africa',
  GQ: 'central-africa', TD: 'central-africa', ST: 'central-africa',
  BW: 'southern-africa', LS: 'southern-africa', MW: 'southern-africa', MZ: 'southern-africa', NA: 'southern-africa', SZ: 'southern-africa',
  ZA: 'southern-africa', ZM: 'southern-africa', ZW: 'southern-africa', MG: 'southern-africa', MU: 'southern-africa'
};

const normalized = rows.map((r) => {
  const rel = r.raw || r.raw_articles || r.raw_article || r.rawArticles;
  const raw = Array.isArray(rel) ? (rel[0] || {}) : (rel || {});
  const country = String(r.country || 'PAN').toUpperCase();
  return {
    raw_id: r.raw_id || r.id,
    country,
    sector: r.sector || 'Other',
    relevance_score: Number(r.relevance_score || 0),
    relevance_reason: r.relevance_reason || '',
    summary: r.summary || '',
    enriched_at: r.enriched_at || '',
    headline: raw.headline || r.headline || '',
    url: raw.url || r.url || '',
    source_name: raw.source_name || r.source_name || 'Unknown',
    published_at: raw.published_at || raw.scraped_at || r.published_at || r.scraped_at || '',
    region: regionByCountry[country] || (country === 'PAN' ? 'pan-africa' : 'other')
  };
});

let filtered = normalized;
if (req.region && req.region !== 'all') {
  filtered = filtered.filter((r) => r.region === req.region);
}

let themeNotes = '';
if (req.theme) {
  const theme = String(req.theme).toLowerCase();
  const keywords = theme.split(/[\s,]+/).filter((k) => k.length >= 4);
  const themeMatched = filtered.filter((r) => {
    const blob = `${r.headline} ${r.summary}`.toLowerCase();
    if (blob.includes(theme)) return true;
    return keywords.some((k) => blob.includes(k));
  });
  if (themeMatched.length >= 5) {
    filtered = themeMatched;
  } else {
    themeNotes = `Theme '${req.theme}' had low direct matches (${themeMatched.length}); using broader evidence set.`;
  }
}

const dedup = [];
const seen = new Set();
for (const row of filtered) {
  const key = row.url || `raw:${row.raw_id}`;
  if (seen.has(key)) continue;
  seen.add(key);
  dedup.push(row);
}

const topRows = dedup.slice(0, Math.min(dedup.length, 90));

return [{
  json: {
    ...req,
    has_articles: topRows.length > 0,
    article_count: topRows.length,
    theme_filter_note: themeNotes,
    evidence_rows: topRows
  }
}];

const payload = {
  request: {
    requester: $json.requester,
    requested_at_utc: $json.requested_at_utc,
    audience: $json.audience,
    filters: {
      country: $json.country,
      sector: $json.sector,
      region: $json.region,
      theme: $json.theme,
      days: $json.days,
      min_relevance: $json.min_relevance,
      max_articles: $json.max_articles
    },
    theme_filter_note: $json.theme_filter_note
  },
  evidence: $json.evidence_rows
};

const systemPrompt = [
  'You are IOA Briefing Analyst, producing concise executive intelligence briefs on African markets.',
  'Return ONLY strict JSON.',
  'Never invent evidence, URLs, countries, sectors, or claims.',
  'Every key claim must be backed by one or more URLs from provided evidence.',
  'Use only the provided evidence rows. If evidence is thin, say so clearly.',
  'Output keys exactly: title, executive_summary, key_findings, country_or_region_hotspots, sector_view, risk_watchlist, opportunity_watchlist, references, slack_digest.',
  'key_findings: array of objects {finding, why_it_matters, evidence_urls}.',
  'country_or_region_hotspots: array of objects {location, note, evidence_urls}.',
  'sector_view: array of objects {sector, note, evidence_urls}.',
  'references: array of objects {headline, url, source_name, country, sector, published_at}.',
  'slack_digest: <= 1200 characters, bullet style, include top references as markdown links.'
].join('\n');

const userPrompt = JSON.stringify(payload);

return [{
  json: {
    ...$json,
    system_prompt: systemPrompt,
    user_prompt: userPrompt
  }
}];

const req = $items('Prepare Evidence Set', 0, 0)[0].json;
const raw = String($json.choices?.[0]?.message?.content || '{}').trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (err) {
  parsed = {
    title: 'IOA Brief (Parse Error)',
    executive_summary: 'Model output was not valid JSON. Check workflow logs.',
    key_findings: [],
    country_or_region_hotspots: [],
    sector_view: [],
    risk_watchlist: [],
    opportunity_watchlist: [],
    references: req.evidence_rows.slice(0, 10).map((r) => ({
      headline: r.headline,
      url: r.url,
      source_name: r.source_name,
      country: r.country,
      sector: r.sector,
      published_at: r.published_at
    })),
    slack_digest: 'Layer 3 parse error. See n8n execution details.'
  };
}

const refs = Array.isArray(parsed.references) ? parsed.references.slice(0, 8) : [];
const refLines = refs.map((r, i) => `${i + 1}. <${r.url}|${r.headline || r.url}> (${r.source_name || 'Unknown'})`).join('\n');

const filterLine = `Filters: country=${req.country}, sector=${req.sector}, region=${req.region}, theme=${req.theme || 'none'}, days=${req.days}`;
const header = `*${parsed.title || 'IOA Brief'}*\n${filterLine}\nEvidence used: ${req.article_count}`;
const digest = String(parsed.slack_digest || '').trim();

const slackText = [header, digest, refLines ? `Top references:\n${refLines}` : 'Top references: none'].filter(Boolean).join('\n\n');

return [{
  json: {
    ...req,
    brief_json: parsed,
    slack_text: slackText
  }
}];
